// Parse storage information
const output = $input.first().json.stdout;
const lines = output.split('\n');

let totalMB = 0;
let availableMB = 0;
let usedMB = 0;
let usedPercent = 0;
let availablePercent = 0;

lines.forEach(line => {
  if (line.includes('total_mb:')) totalMB = parseInt(line.split(':')[1]);
  if (line.includes('available_mb:')) availableMB = parseInt(line.split(':')[1]);
  if (line.includes('used_mb:')) usedMB = parseInt(line.split(':')[1]);
  if (line.includes('used_percent:')) usedPercent = parseInt(line.split(':')[1]);
  if (line.includes('available_percent:')) availablePercent = parseInt(line.split(':')[1]);
});

// Determine alert level
let alertLevel = 'normal';
let alertMessage = '';
let shouldAlert = false;

if (availablePercent <= 5) {
  alertLevel = 'critical';
  alertMessage = '🚨 CRITICAL: Less than 5% storage remaining!';
  shouldAlert = true;
} else if (availablePercent <= 10) {
  alertLevel = 'high';
  alertMessage = '⚠️ HIGH: Less than 10% storage remaining!';
  shouldAlert = true;
} else if (availablePercent <= 20) {
  alertLevel = 'medium';
  alertMessage = '⚡ MEDIUM: Less than 20% storage remaining!';
  shouldAlert = true;
} else {
  alertLevel = 'normal';
  alertMessage = '✅ Storage levels normal';
  shouldAlert = false;
}

return [{
  json: {
    total_mb: totalMB,
    available_mb: availableMB,
    used_mb: usedMB,
    used_percent: usedPercent,
    available_percent: availablePercent,
    alert_level: alertLevel,
    alert_message: alertMessage,
    should_alert: shouldAlert,
    timestamp: new Date().toISOString(),
    formatted_total: `${(totalMB / 1024).toFixed(1)} GB`,
    formatted_available: `${(availableMB / 1024).toFixed(1)} GB`,
    formatted_used: `${(usedMB / 1024).toFixed(1)} GB`
  }
}];
